[{"text": "#!/usr/bin/env python3\n\"\"\"\n\u5fae\u535a\u70ed\u641c/\u8bdd\u9898\u91c7\u96c6\u5668\n\u6570\u636e\u6e90\uff1a\u5fae\u535a\u516c\u5f00\u9875\u9762\n\"\"\"\n\nimport json\nimport time\nimport os\nimport urllib.request\nimport urllib.error\nimport re\nfrom datetime import datetime\nfrom typing import List, Dict, Any, Optional\n\n# \u91c7\u96c6\u914d\u7f6e\nCONFIG = {\n    'output_dir': '../data/raw/weibo',\n    'delay_seconds': 2,\n}\n\n# \u641c\u7d22\u5173\u952e\u8bcd\u914d\u7f6e\nCATEGORY_KEYWORDS = {\n    'wechat': [\n        '\u5fae\u4fe1\u5d29\u4e86', '\u5fae\u4fe1bug', '\u5fae\u4fe1\u529f\u80fd', '\u5fae\u4fe1\u66f4\u65b0',\n        '\u5fae\u4fe1\u6155\u4e86', '\u5fae\u4fe1\u8f6c\u6587\u5b57', '\u5fae\u4fe1\u8bed\u97f3',\n    ],\n    'social': [\n        '\u5c0f\u7ea2\u4e66bug', '\u5fae\u535abug', 'Soul\u5c01\u53f7', '\u63a2\u63a2\u8d28\u91cf',\n        '\u793e\u4ea4\u8f6f\u4ef6', '\u4ea4\u53cb\u8f6f\u4ef6', '\u7ea6\u4f1aapp',\n    ],\n    'ai': [\n        'ChatGPT\u5d29\u4e86', 'Kimi\u5d29\u4e86', '\u8c46\u5305bug', 'AI\u5e7b\u89c9',\n        'AI\u52a9\u624b', '\u667a\u8c31\u6e05\u8a00', 'AI\u804a\u5929', '\u6587\u5fc3\u4e00\u8a00',\n    ],\n    'more': [\n        '\u9489\u9489bug', '\u9489\u9489\u5d29\u4e86', '\u98de\u4e66bug', '\u817e\u8baf\u4f1a\u8baebug',\n        'Zoom\u5361\u987f', '\u4f01\u4e1a\u5fae\u4fe1', '\u6253\u5361\u5931\u8d25',\n    ],\n}\n\n\ndef fetch_weibo_search(keyword: str) -> List[Dict]:\n    \"\"\"\n    \u4ece\u5fae\u535a\u641c\u7d22\u83b7\u53d6\u76f8\u5173\u5fae\u535a\n    \u6ce8\u610f\uff1a\u5fae\u535a\u6709\u53cd\u722c\u673a\u5236\uff0c\u6210\u529f\u7387\u4e0d\u9ad8\n    \"\"\"\n    encoded_keyword = urllib.parse.quote(keyword)\n    url = f'https://m.weibo.cn/api/container/getIndex?containerid=100103type%3D1%26q%3D{encoded_keyword}&page_type=searchall'\n    \n    try:\n        req = urllib.request.Request(url, headers={\n            'User-Agent': 'Mozilla/5.0 (iPhone; CPU iPhone OS 14_0 like Mac OS X) AppleWebKit/605.1.15',\n            'Accept': 'application/json',\n            'Referer': 'https://m.weibo.cn/',\n        })\n        with urllib.request.urlopen(req, timeout=30) as response:\n            data = json.loads(response.read().decode('utf-8'))\n        \n        posts = []\n        cards = data.get('data', {}).get('cards', [])\n        \n        for card in cards:\n            if card.get('card_type') == 9:  # \u5fae\u535a\u5361\u7247\n                mblog = card.get('mblog', {})\n                if mblog:\n                    # \u6e05\u7406 HTML\n                    text = mblog.get('text', '')\n                    text = re.sub(r'<[^>]+>', '', text)\n                    \n                    posts.append({\n                        'id': mblog.get('id', ''),\n                        'author': mblog.get('user', {}).get('screen_name', ''),\n                        'content': text,\n                        'reposts_count': mblog.get('reposts_count', 0),\n                        'comments_count': mblog.get('comments_count', 0),\n                        'attitudes_count': mblog.get('attitudes_count', 0),\n                        'created_at': mblog.get('created_at', ''),\n                        'keyword': keyword,\n                        'source': '\u5fae\u535a',\n                        'source_url': f\"https://m.weibo.cn/detail/{mblog.get('id', '')}\",\n                    })\n        \n        return posts\n        \n    except Exception as e:\n        print(f\"  Error fetching '{keyword}': {e}\")\n        return []\n\n\ndef crawl_category(category_id: str) -> Dict[str, Any]:\n    \"\"\"\u91c7\u96c6\u5355\u4e2a\u7c7b\u76ee\"\"\"\n    \n    print(f\"\\n{'='*50}\")\n    print(f\"\u5fae\u535a\u91c7\u96c6: {category_id}\")\n    print(f\"{'='*50}\")\n    \n    if category_id not in CATEGORY_KEYWORDS:\n        return {'category': category_id, 'posts': [], 'error': 'Unknown category'}\n    \n    all_posts = []\n    keywords_crawled = []\n    seen_ids = set()\n    \n    for keyword in CATEGORY_KEYWORDS[category_id]:\n        print(f\"\\n\ud83d\udd0d \u641c\u7d22: '{keyword}'\")\n        \n        posts = fetch_weibo_search(keyword)\n        \n        # \u53bb\u91cd\n        unique_posts = []\n        for p in posts:\n            if p.get('id') and p['id'] not in seen_ids:\n                seen_ids.add(p['id'])\n                unique_posts.append(p)\n        \n        all_posts.extend(unique_posts)\n        keywords_crawled.append({\n            'keyword': keyword,\n            'post_count': len(unique_posts),\n        })\n        \n        print(f\"  \u2713 '{keyword}': {len(unique_posts)} \u6761\u5fae\u535a\")\n        time.sleep(CONFIG['delay_seconds'])\n    \n    return {\n        'category': category_id,\n        'crawl_date': datetime.now().isoformat(),\n        'keywords_crawled': keywords_crawled,\n        'total_posts': len(all_posts),\n        'posts': all_posts,\n        'source': '\u5fae\u535a',\n        'note': '\u516c\u5f00\u9875\u9762\u6293\u53d6\uff0c\u6709\u53cd\u722c\u9650\u5236',\n    }\n\n\ndef save_results(category_id: str, data: Dict):\n    \"\"\"\u4fdd\u5b58\u7ed3\u679c\"\"\"\n    output_dir = os.path.join(os.path.dirname(__file__), CONFIG['output_dir'])\n    os.makedirs(output_dir, exist_ok=True)\n    \n    filename = f\"{category_id}_{datetime.now().strftime('%Y%m%d')}.json\"\n    filepath = os.path.join(output_dir, filename)\n    \n    with open(filepath, 'w', encoding='utf-8') as f:\n        json.dump(data, f, ensure_ascii=False, indent=2)\n    \n    print(f\"\\n\ud83d\udcbe \u4fdd\u5b58\u5230: {filepath}\")\n    return filepath\n\n\ndef main(categories: Optional[List[str]] = None):\n    \"\"\"\u4e3b\u51fd\u6570\"\"\"\n    import urllib.parse\n    \n    target_categories = categories or list(CATEGORY_KEYWORDS.keys())\n    \n    print(\"=\" * 60)\n    print(\"\u5fae\u535a\u91c7\u96c6\u5668\")\n    print(\"\u6570\u636e\u6e90: \u5fae\u535a\u516c\u5f00\u9875\u9762\")\n    print(f\"\u76ee\u6807\u7c7b\u76ee: {', '.join(target_categories)}\")\n    print(\"=\" * 60)\n    print(\"\\n\u26a0\ufe0f \u6ce8\u610f: \u5fae\u535a\u6709\u53cd\u722c\u673a\u5236\uff0c\u90e8\u5206\u8bf7\u6c42\u53ef\u80fd\u5931\u8d25\")\n    \n    results = {}\n    \n    for cat_id in target_categories:\n        data = crawl_category(cat_id)\n        filepath = save_results(cat_id, data)\n        results[cat_id] = {\n            'file': filepath,\n            'total': data['total_posts'],\n        }\n    \n    print(\"\\n\" + \"=\" * 60)\n    print(\"\u91c7\u96c6\u5b8c\u6210\u6c47\u603b:\")\n    total = 0\n    for cat_id, info in results.items():\n        print(f\"  {cat_id}: {info['total']} \u6761\")\n        total += info['total']\n    print(f\"  \u603b\u8ba1: {total} \u6761\")\n    print(\"=\" * 60)\n    \n    return results\n\n\nif __name__ == '__main__':\n    import sys\n    import urllib.parse\n    categories = sys.argv[1:] if len(sys.argv) > 1 else None\n    main(categories)\n", "type": "text"}]